code.glsl:
in vec2 vTexCoord;
in vec4 vVertColor;
in vec3 vWorldPos;

layout(location = 0) out vec4 fragColor;

void main() {
    vec4 color = texture(sTD2DInputs[0], vTexCoord);
    color *= vVertColor;
    fragColor = TDOutputSwizzle(color);
}

code.vertexGlsl:
out vec2 vTexCoord;
out vec4 vVertColor;
out vec3 vWorldPos;

void main() {
    vec4 worldPos = TDDeform(P);
    vTexCoord  = uv[0].st;
    vVertColor = Cd;
    vWorldPos  = worldPos.xyz;
    gl_Position = TDWorldToProj(worldPos);
}
